	@Test
	void debugLoggingKeepsNormalDiagnosticsCompact() throws Exception {
		JoinOrderPlanner.JoinOrderPlan plan = planTwoFactorGreedyJoin();

		String logOutput = logOutput();

		assertThat(logOutput)
				.contains("Sketch join planner input:")
				.contains("originalOrder=")
				.contains("pareto beam")
				.contains("result: order=")
				.contains("outputRows=")
				.contains("totalWorkRows=")
				.contains("SP(?x urn:pB ?y)")
				.doesNotContain("estimate factor[")
				.doesNotContain("joinVars=")
				.doesNotContain("finalFrontier[0]");

		assertThat(diagnostics(plan))
				.anySatisfy(line -> assertThat(line).contains("pareto beam"))
				.anySatisfy(line -> assertThat(line).contains("result: order="))
				.noneSatisfy(line -> assertThat(line).contains("estimate factor["))
				.noneSatisfy(line -> assertThat(line).contains("joinVars="))
				.noneSatisfy(line -> assertThat(line).contains("finalFrontier[0]"));
	}

	@Test
	void traceDiagnosticsExplainGreedyReorderDecision() throws Exception {
		System.setProperty(TRACE_DIAGNOSTICS_PROPERTY, "true");

		JoinOrderPlanner.JoinOrderPlan plan = planTwoFactorGreedyJoin();

		String logOutput = logOutput();

		assertThat(logOutput)
				.contains("Sketch join planner input:")
				.contains("originalOrder=")
				.contains("factor[0]")
				.contains("factor[1]")
				.contains("pareto beam")
				.contains("finalFrontier[0]")
				.contains("result: order=")
				.contains("outputRows=")
				.contains("totalWorkRows=")
				.contains("SP(?x urn:pB ?y)");

		assertThat(diagnostics(plan))
				.anySatisfy(line -> assertThat(line).contains("pareto beam"))
				.anySatisfy(line -> assertThat(line).contains("finalFrontier[0]"))
				.anySatisfy(line -> assertThat(line).contains("result: order="));
	}

	@Test
	void traceDiagnosticsIncludePerFactorEstimates() throws Exception {
		System.setProperty(TRACE_DIAGNOSTICS_PROPERTY, "true");

		JoinOrderPlanner.JoinOrderPlan plan = planTwoFactorGreedyJoin();

		String logOutput = logOutput();

		assertThat(logOutput)
				.contains("estimate factor[0]:")
				.contains("baseRows=")
				.contains("joinVars=");

		assertThat(diagnostics(plan))
				.anySatisfy(line -> assertThat(line).contains("estimate factor[0]:"))
				.anySatisfy(line -> assertThat(line).contains("estimate factor[1]:"));
	}

	@Test
	void lmdbPlanAlternativesPropertyLogsCostedAlternatives() throws Exception {
		System.setProperty(LMDB_PLAN_ALTERNATIVES_PROPERTY, "true");

		JoinOrderPlanner.JoinOrderPlan plan = planTwoFactorGreedyJoin();

		String logOutput = logOutput();

		assertThat(logOutput)
				.contains("pareto beam")
				.contains("finalFrontier[0]")
				.contains("JoinCostVector")
				.contains("totalWorkRows=")
				.contains("finalRows=");

		assertThat(diagnostics(plan))
				.anySatisfy(line -> assertThat(line).contains("finalFrontier[0]"))
				.anySatisfy(line -> assertThat(line).contains("JoinCostVector"));
	}

	private static JoinOrderPlanner.JoinOrderPlan planTwoFactorGreedyJoin() {
		StubSketchStatementSource store = new StubSketchStatementSource();
		IRI pA = VF.createIRI("urn:pA");
		IRI pB = VF.createIRI("urn:pB");
		IRI y = VF.createIRI("urn:y");

		for (int i = 0; i < 512; i++) {
			Resource s = VF.createIRI("urn:s" + i);
			IRI x = VF.createIRI("urn:x" + i);
			store.add(VF.createStatement(s, pA, x));
		}
		store.add(VF.createStatement(VF.createIRI("urn:x0"), pB, y));

		SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(store, config());
		estimator.rebuild();

		StatementPattern a = pattern("s", pA, "x");
		StatementPattern b = pattern("x", pB, "y");
		List<TupleExpr> args = List.of(a, b);

		return estimator.planJoinOrder(args, Set.of(), JoinOrderPlanner.Algorithm.GREEDY).orElseThrow();
	}

	private String logOutput() {
		return listAppender.list.stream()
				.map(ILoggingEvent::getFormattedMessage)
				.collect(Collectors.joining("\n"));
	}

	@SuppressWarnings("unchecked")
	private static List<String> diagnostics(JoinOrderPlanner.JoinOrderPlan plan) throws Exception {
		Method method = plan.getClass().getMethod("getDiagnostics");
		return (List<String>) method.invoke(plan);
	}

	private static StatementPattern pattern(String subjVar, IRI predicate, String objVar) {
		return new StatementPattern(Var.of(subjVar), Var.of("p", predicate), Var.of(objVar));
	}

	private static SketchBasedJoinEstimator.Config config() {
		return SketchBasedJoinEstimator.Config.defaults()
				.withNominalEntries(64)
				.withThrottleEveryN(1)
				.withThrottleMillis(0)
				.withRefreshSleepMillis(5);
	}
